def is_duplicate(text_a, text_b, threshold= 0.8):
    a= set(text_a.split())
    b= set(text_b.split())
    if not len(a): return text_b
    if not len(b): return text_a
    intersection = a.intersection(b)
    score= len(intersection)/(min(len(a), len(b)) + 1e-9)
    return score>=threshold

def merge_duplicate(objs:List[str])-> List[str]:
    results=[]
    merged= set()
    n= len(objs)
    for el, score in objs:
        if el in merged:
            continue
        temp_score=score
        for i in range(n):        
            o_el, o_score= objs[i]
            if is_duplicate(el, o_el):
                temp_score+=o_score
                merged.add(o_el)
        results.append((el, temp_score))
    return results
    
